    async function uploadFile(event) {
        const file = event.target.files[0];
        if (!file) return;

        let projectName = prompt("Enter a name for this Tax Year/Workspace (e.g., 2025_Jacob):");
        if (!projectName) return;

        const formData = new FormData();
        formData.append('file', file);
        formData.append('project_name', projectName);

        document.getElementById('trip-list').innerHTML = '<p style="text-align: center; color: var(--text-muted); margin-top: 40px;">Uploading and crunching data... this may take a minute.</p>';

        try {
            const response = await fetch('/api/upload', {
                method: 'POST',
                body: formData
            });
            const result = await response.json();
            if (response.ok) {
                alert('Success! ' + result.message);
